337 | /// Forward bus events to the A2A server for observability
338 | async fn forward_bus_event(
339 |     client: &Client,
340 |     server: &str,
341 |     token: &str,
342 |     worker_id: &str,
343 |     envelope: &BusEnvelope,
344 | ) -> Result<()> {
345 |     // Only forward certain event types
346 |     let payload = match &envelope.message {
347 |         BusMessage::AgentReady {
348 |             agent_id,
349 |             capabilities,
350 |         } => {
351 |             serde_json::json!({
352 |                 "type": "agent_ready",
353 |                 "worker_id": worker_id,
354 |                 "agent_id": agent_id,
355 |                 "capabilities": capabilities,
356 |             })
357 |         }
358 |         BusMessage::TaskUpdate {
359 |             task_id,
360 |             state,
361 |             message,
362 |         } => {
363 |             serde_json::json!({
364 |                 "type": "task_update",
365 |                 "worker_id": worker_id,
366 |                 "task_id": task_id,
367 |                 "state": format!("{:?}", state),
368 |                 "message": message,
369 |             })
370 |         }
371 |         BusMessage::AgentMessage { from, to, parts } => {
372 |             let text = parts
373 |                 .iter()
374 |                 .filter_map(|p| {
375 |                     if let crate::a2a::types::Part::Text { text } = p {
376 |                         Some(text.clone())
377 |                     } else {
378 |                         None
379 |                     }
380 |                 })
381 |                 .collect::<Vec<_>>()
382 |                 .join("\n");
383 | 
384 |             serde_json::json!({
385 |                 "type": "agent_message",
386 |                 "worker_id": worker_id,
387 |                 "from": from,
388 |                 "to": to,
389 |                 "text": text,
390 |             })
391 |         }
392 |         // Skip other event types for now
393 |         _ => return Ok(()),
394 |     };
395 | 
396 |     let url = format!("{}/v1/agent/workers/{}/events", server, worker_id);
397 |     let res = client
398 |         .post(&url)
399 |         .bearer_auth(token)
400 |         .json(&payload)
401 |         .send()
402 |         .await?;
403 | 
404 |     if !res.status().is_success() {
405 |         tracing::debug!("Failed to forward bus event: {}", res.status());
406 |     }
407 | 
408 |     Ok(())
409 | }

