 82 | fn resolve_rlm_provider_and_model(
 83 |     model_arg: Option<&str>,
 84 |     registry: &provider::ProviderRegistry,
 85 | ) -> anyhow::Result<(Arc<dyn provider::Provider>, String, String)> {
 86 |     if let Some(model_ref) = model_arg {
 87 |         let (provider_name, model_name) = provider::parse_model_string(model_ref);
 88 |         if let Some(provider_name) = provider_name {
 89 |             let normalized = normalize_provider_alias(provider_name);
 90 |             if normalized == "local_cuda" {
 91 |                 let provider = registry.get("local_cuda").ok_or_else(|| {
 92 |                     anyhow::anyhow!(
 93 |                         "local_cuda selected explicitly but provider is unavailable. \
 94 |                          Build/install with CUDA support \
 95 |                          (--features candle-cuda) and set \
 96 |                          LOCAL_CUDA_MODEL_PATH + LOCAL_CUDA_TOKENIZER_PATH."
 97 |                     )
 98 |                 })?;
 99 |                 if !local_cuda_runtime_configured() {
100 |                     anyhow::bail!(
101 |                         "local_cuda selected explicitly but runtime is not configured. \
102 |                          Set LOCAL_CUDA_MODEL_PATH and LOCAL_CUDA_TOKENIZER_PATH \
103 |                          (or CODETETHER_LOCAL_CUDA_MODEL_PATH / CODETETHER_LOCAL_CUDA_TOKENIZER_PATH)."
104 |                     );
105 |                 }
106 |                 return Ok((provider, model_name.to_string(), "local_cuda".to_string()));
107 |             }
108 | 
109 |             let provider = registry.get(normalized).ok_or_else(|| {
110 |                 anyhow::anyhow!(
111 |                     "Requested provider '{}' is not available. Configure it in Vault or env.",
112 |                     normalized
113 |                 )
114 |             })?;
115 |             return Ok((provider, model_name.to_string(), normalized.to_string()));
116 |         }
117 | 
118 |         // Unqualified model: local_cuda first when usable, then openrouter.
119 |         if local_cuda_runtime_configured() {
120 |             if let Some(provider) = registry.get("local_cuda") {
121 |                 return Ok((provider, model_ref.to_string(), "local_cuda".to_string()));
122 |             }
123 |             anyhow::bail!(
124 |                 "Local CUDA is configured but unavailable. \
125 |                  Fix local CUDA setup (CUDA-enabled binary + valid LOCAL_CUDA_MODEL_PATH and \
126 |                  LOCAL_CUDA_TOKENIZER_PATH) or explicitly select OpenRouter with \
127 |                  --model openrouter/<model>."
128 |             );
129 |         }
130 |         if let Some(provider) = registry.get("openrouter") {
131 |             return Ok((provider, model_ref.to_string(), "openrouter".to_string()));
132 |         }
133 |         anyhow::bail!(
134 |             "No provider available for model '{}'. Configure local_cuda or openrouter.",
135 |             model_ref
136 |         );
137 |     }
138 | 
139 |     // No explicit model: prefer local_cuda when usable, otherwise openrouter.
140 |     if local_cuda_runtime_configured() {
141 |         if let Some(provider) = registry.get("local_cuda") {
142 |             return Ok((provider, local_cuda_model_name(), "local_cuda".to_string()));
143 |         }
144 |         anyhow::bail!(
145 |             "Local CUDA is configured but unavailable. \
146 |              Fix local CUDA setup (CUDA-enabled binary + valid LOCAL_CUDA_MODEL_PATH and \
147 |              LOCAL_CUDA_TOKENIZER_PATH) or disable local CUDA env vars to use OpenRouter fallback."
148 |         );
149 |     }
150 | 
151 |     if let Some(provider) = registry.get("openrouter") {
152 |         return Ok((
153 |             provider,
154 |             default_openrouter_rlm_model(),
155 |             "openrouter".to_string(),
156 |         ));
157 |     }
158 | 
159 |     anyhow::bail!(
160 |         "No usable RLM provider found. Configure local CUDA \
161 |          (LOCAL_CUDA_MODEL_PATH + LOCAL_CUDA_TOKENIZER_PATH) \
162 |          or OpenRouter credentials."
163 |     );
164 | }
