166 | fn gather_rlm_content(args: &cli::RlmArgs) -> anyhow::Result<String> {
167 |     use std::io::Read;
168 | 
169 |     if !args.file.is_empty() {
170 |         let mut parts = Vec::new();
171 |         for path in &args.file {
172 |             match std::fs::read_to_string(path) {
173 |                 Ok(content) => parts.push(format!(
174 |                     "=== FILE: {} ===\n{}\n=== END FILE ===\n",
175 |                     path.display(),
176 |                     content
177 |                 )),
178 |                 Err(e) => parts.push(format!(
179 |                     "=== FILE: {} ===\nError: {}\n=== END FILE ===\n",
180 |                     path.display(),
181 |                     e
182 |                 )),
183 |             }
184 |         }
185 |         return Ok(parts.join("\n"));
186 |     }
187 | 
188 |     if let Some(ref c) = args.content {
189 |         if c == "-" {
190 |             let mut stdin_content = String::new();
191 |             std::io::stdin().read_to_string(&mut stdin_content)?;
192 |             return Ok(stdin_content);
193 |         }
194 |         return Ok(c.clone());
195 |     }
196 | 
197 |     anyhow::bail!("Either --file or --content must be provided");
198 | }
