{"path":"src/tui/app/state.rs","content":"use crate::session::SessionSummary;
use crate::tui::bus_log::BusLogState;
use crate::tui::chat::message::ChatMessage;
use crate::tui::models::{InputMode, ViewMode};
use crate::tui::ralph_view::RalphViewState;
use crate::tui::swarm_view::SwarmViewState;
use crate::tui::symbol_search::SymbolSearchState;

pub use crate::session::SessionEvent;
pub use crate::tui::ralph_view::RalphEvent;
pub use crate::tui::swarm_view::SwarmEvent;

#[derive(Default)]
pub struct App {
    pub state: AppState,
}

pub struct AppState {
    pub view_mode: ViewMode,
    pub input_mode: InputMode,
    pub messages: Vec<ChatMessage>,
    pub input: String,
    pub input_cursor: usize,
    pub input_scroll: usize,
    pub chat_scroll: usize,
    pub status: String,
    pub processing: bool,
    pub session_id: Option<String>,
    pub sessions: Vec<SessionSummary>,
    pub selected_session: usize,
    pub cwd_display: String,
    pub bus_log: BusLogState,
    pub swarm: SwarmViewState,
    pub ralph: RalphViewState,
    pub symbol_search: SymbolSearchState,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            view_mode: ViewMode::Chat,
            input_mode: InputMode::Normal,
            messages: vec![],
            input: String::new(),
            input_cursor: 0,
            input_scroll: 0,
            chat_scroll: 0,
            status: "Ready — type a message and press Enter. Ctrl+C/Ctrl+Q quits.".to_string(),
            processing: false,
            session_id: None,
            sessions: vec![],
            selected_session: 0,
            cwd_display: String::new(),
            bus_log: BusLogState::new(),
            swarm: SwarmViewState::new(),
            ralph: RalphViewState::new(),
            symbol_search: SymbolSearchState::new(),
        }
    }
}

impl AppState {
    pub fn clamp_input_cursor(&mut self) {
        self.input_cursor = self.input_cursor.min(self.input.len());
    }

    pub fn ensure_input_cursor_visible(&mut self, visible_width: usize) {
        if visible_width == 0 {
            self.input_scroll = self.input_cursor;
            return;
        }
        if self.input_cursor < self.input_scroll {
            self.input_scroll = self.input_cursor;
        } else if self.input_cursor >= self.input_scroll.saturating_add(visible_width) {
            self.input_scroll = self
                .input_cursor
                .saturating_sub(visible_width.saturating_sub(1));
        }
    }

    pub fn move_cursor_left(&mut self) {
        if self.input_cursor > 0 {
            self.input_cursor -= 1;
        }
    }

    pub fn move_cursor_right(&mut self) {
        if self.input_cursor < self.input.len() {
            self.input_cursor += 1;
        }
    }

    pub fn move_cursor_word_left(&mut self) {
        self.clamp_input_cursor();
        while self.input_cursor > 0
            && self.input.as_bytes()[self.input_cursor - 1].is_ascii_whitespace()
        {
            self.input_cursor -= 1;
        }
        while self.input_cursor > 0
            && !self.input.as_bytes()[self.input_cursor - 1].is_ascii_whitespace()
        {
            self.input_cursor -= 1;
        }
    }

    pub fn move_cursor_word_right(&mut self) {
        self.clamp_input_cursor();
        while self.input_cursor < self.input.len()
            && self.input.as_bytes()[self.input_cursor].is_ascii_whitespace()
        {
            self.input_cursor += 1;
        }
        while self.input_cursor < self.input.len()
            && !self.input.as_bytes()[self.input_cursor].is_ascii_whitespace()
        {
            self.input_cursor += 1;
        }
    }

    pub fn move_cursor_home(&mut self) {
        self.input_cursor = 0;
    }

    pub fn move_cursor_end(&mut self) {
        self.input_cursor = self.input.len();
    }

    pub fn insert_char(&mut self, c: char) {
        self.clamp_input_cursor();
        self.input.insert(self.input_cursor, c);
        self.input_cursor += c.len_utf8();
    }

    pub fn delete_backspace(&mut self) {
        self.clamp_input_cursor();
        if self.input_cursor == 0 {
            return;
        }
        self.input_cursor -= 1;
        self.input.remove(self.input_cursor);
    }

    pub fn delete_forward(&mut self) {
        self.clamp_input_cursor();
        if self.input_cursor >= self.input.len() {
            return;
        }
        self.input.remove(self.input_cursor);
    }

    pub fn scroll_up(&mut self, amount: usize) {
        self.chat_scroll = self.chat_scroll.saturating_sub(amount);
    }

    pub fn scroll_down(&mut self, amount: usize) {
        self.chat_scroll = self.chat_scroll.saturating_add(amount);
    }

    pub fn scroll_to_bottom(&mut self) {
        self.chat_scroll = usize::MAX / 2;
    }

    pub fn sessions_select_prev(&mut self) {
        if self.selected_session > 0 {
            self.selected_session -= 1;
        }
    }

    pub fn sessions_select_next(&mut self) {
        if self.selected_session + 1 < self.sessions.len() {
            self.selected_session += 1;
        }
    }

    pub fn set_view_mode(&mut self, view_mode: ViewMode) {
        self.view_mode = view_mode;
    }
}
"}

{"path":"src/tui/ui/main.rs","content":"use ratatui::{
    layout::{Constraint, Direction, Layout},
    style::{Color, Style, Stylize},
    text::{Line, Span},
    widgets::{Block, Borders, List, ListItem, ListState, Paragraph, Wrap},
    Frame,
};

use crate::tui::app::state::App;
use crate::tui::bus_log::render_bus_log;
use crate::tui::chat::message::MessageType;
use crate::tui::help::render_help;
use crate::tui::lsp::render_lsp;
use crate::tui::models::ViewMode;
use crate::tui::ralph_view::render_ralph_view;
use crate::tui::rlm::render_rlm;
use crate::tui::settings::render_settings;
use crate::tui::swarm_view::render_swarm_view;
use crate::tui::symbol_search::render_symbol_search;

fn clamp_scroll(scroll: usize) -> u16 {
    scroll.min(u16::MAX as usize) as u16
}

pub fn ui(f: &mut Frame, app: &mut App) {
    match app.state.view_mode {
        ViewMode::Chat => render_chat_view(f, app),
        ViewMode::Sessions => render_sessions_view(f, app),
        ViewMode::Swarm => render_swarm_view(f, &mut app.state.swarm, f.area()),
        ViewMode::Ralph => render_ralph_view(f, &mut app.state.ralph, f.area()),
        ViewMode::Bus => render_bus_log(f, &mut app.state.bus_log, f.area()),
        ViewMode::Help => render_help(f, f.area()),
        ViewMode::Settings => render_settings(f, f.area(), &app.state.status),
        ViewMode::Lsp => render_lsp(f, f.area(), &app.state.cwd_display, &app.state.status),
        ViewMode::Rlm => render_rlm(f, f.area(), &app.state.cwd_display, &app.state.status),
    }

    if app.state.symbol_search.loading
        || !app.state.symbol_search.query.is_empty()
        || !app.state.symbol_search.results.is_empty()
        || app.state.symbol_search.error.is_some()
    {
        render_symbol_search(f, &mut app.state.symbol_search, f.area());
    }
}

fn render_chat_view(f: &mut Frame, app: &mut App) {
    let area = f.area();
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(3),
            Constraint::Min(8),
            Constraint::Length(3),
            Constraint::Length(3),
        ])
        .split(area);

    let title = if app.state.processing {
        "CodeTether TUI — processing"
    } else {
        "CodeTether TUI"
    };

    let session_text = app
        .state
        .session_id
        .as_deref()
        .map(|id| format!("session {id}"))
        .unwrap_or_else(|| "new session".to_string());

    let header = Paragraph::new(vec![Line::from(vec![
        Span::raw("Status: ").dim(),
        Span::styled(
            app.state.status.clone(),
            Style::default().fg(if app.state.processing {
                Color::Yellow
            } else {
                Color::Green
            }),
        ),
        Span::raw("  •  ").dim(),
        Span::raw(session_text).dim(),
        Span::raw("  •  ").dim(),
        Span::raw("F1 help F2 sessions F3 swarm F4 ralph F5 bus F6 settings F7 lsp F8 rlm").dim(),
    ])])
    .block(Block::default().borders(Borders::ALL).title(title));
    f.render_widget(header, chunks[0]);

    let mut lines: Vec<Line<'static>> = Vec::new();
    if app.state.messages.is_empty() {
        lines.push(Line::from("No messages yet. Type a prompt and press Enter.".dim()));
    } else {
        for msg in &app.state.messages {
            let (label, color) = match msg.message_type {
                MessageType::User => ("You", Color::White),
                MessageType::Assistant => ("Assistant", Color::Cyan),
                MessageType::System => ("System", Color::Green),
                MessageType::Error => ("Error", Color::Red),
            };

            let mut first = true;
            for raw_line in msg.content.lines() {
                let prefix = if first {
                    format!("{label}: ")
                } else {
                    "  ".to_string()
                };
                lines.push(Line::from(vec![
                    Span::styled(prefix, Style::default().fg(color).bold()),
                    Span::raw(raw_line.to_string()),
                ]));
                first = false;
            }
            if first {
                lines.push(Line::from(vec![
                    Span::styled(format!("{label}: "), Style::default().fg(color).bold()),
                    Span::raw(String::new()),
                ]));
            }
            lines.push(Line::from(""));
        }
    }

    let chat = Paragraph::new(lines)
        .block(
            Block::default().borders(Borders::ALL).title(format!(
                "Chat (scroll: {})",
                app.state.chat_scroll.min(u16::MAX as usize)
            )),
        )
        .wrap(Wrap { trim: false })
        .scroll((clamp_scroll(app.state.chat_scroll), 0));
    f.render_widget(chat, chunks[1]);

    let visible_width = chunks[2].width.saturating_sub(2) as usize;
    app.state.ensure_input_cursor_visible(visible_width);
    let visible_input = app
        .state
        .input
        .chars()
        .skip(app.state.input_scroll)
        .take(visible_width)
        .collect::<String>();

    let input = Paragraph::new(visible_input)
        .block(Block::default().borders(Borders::ALL).title("Input"));
    f.render_widget(input, chunks[2]);

    let input_inner_x = chunks[2].x.saturating_add(1);
    let input_inner_y = chunks[2].y.saturating_add(1);
    let cursor_col = app.state.input_cursor.saturating_sub(app.state.input_scroll);
    let cursor_offset = if visible_width == 0 {
        0
    } else {
        cursor_col.min(visible_width.saturating_sub(1)) as u16
    };
    let cursor_x = input_inner_x.saturating_add(cursor_offset);
    f.set_cursor_position((cursor_x, input_inner_y));

    let help = Paragraph::new(
        "Enter send • ↑/↓ scroll • PgUp/PgDn scroll faster • ←/→ move cursor • Ctrl+←/→ word jump • Home/End jump • Del delete-at-cursor • F2 sessions • F5 bus • Backspace delete • Esc normal mode • Ctrl+C/Ctrl+Q quit",
    )
    .block(Block::default().borders(Borders::ALL).title("Help"))
    .wrap(Wrap { trim: true });
    f.render_widget(help, chunks[3]);
}

fn render_sessions_view(f: &mut Frame, app: &mut App) {
    let area = f.area();
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Length(3), Constraint::Min(8), Constraint::Length(3)])
        .split(area);

    let header = Paragraph::new(vec![Line::from(vec![
        Span::raw("Workspace Sessions").cyan().bold(),
        Span::raw("  •  ").dim(),
        Span::raw(app.state.status.clone()).dim(),
    ])])
    .block(Block::default().borders(Borders::ALL).title("Sessions"));
    f.render_widget(header, chunks[0]);

    let items: Vec<ListItem<'static>> = if app.state.sessions.is_empty() {
        vec![ListItem::new("No workspace sessions found")]
    } else {
        app.state
            .sessions
            .iter()
            .map(|session| {
                let title = session
                    .title
                    .clone()
                    .unwrap_or_else(|| "Untitled session".to_string());
                let summary = format!(
                    "{}  •  {} msgs  •  {}",
                    title,
                    session.message_count,
                    session.updated_at.format("%Y-%m-%d %H:%M")
                );
                ListItem::new(summary)
            })
            .collect()
    };

    let mut state = ListState::default();
    if !app.state.sessions.is_empty() {
        state.select(Some(app.state.selected_session.min(app.state.sessions.len() - 1)));
    }

    let list = List::new(items)
        .block(Block::default().borders(Borders::ALL).title("Available Sessions"))
        .highlight_style(Style::default().bg(Color::DarkGray).fg(Color::Cyan).bold())
        .highlight_symbol("> ");
    f.render_stateful_widget(list, chunks[1], &mut state);

    let help = Paragraph::new("↑/↓ select • Enter load selected session • F1/F3/F4/F5/F6/F7/F8 switch views • F2/Esc back to chat • Ctrl+C/Ctrl+Q quit")
        .block(Block::default().borders(Borders::ALL).title("Help"))
        .wrap(Wrap { trim: true });
    f.render_widget(help, chunks[2]);
}
"}

{"path":"src/tui/app/run.rs","content":"use std::io;
use std::sync::Arc;
use std::time::Duration;

use crossterm::{
    event::{self, Event, KeyCode, KeyEventKind, KeyModifiers},
    execute,
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
};
use ratatui::{backend::CrosstermBackend, Terminal};
use tokio::sync::mpsc;

use crate::bus::AgentBus;
use crate::provider::{ContentPart, ProviderRegistry, Role};
use crate::session::{list_sessions_for_directory, Session, SessionEvent};
use crate::tui::app::state::App;
use crate::tui::chat::message::{ChatMessage, MessageType};
use crate::tui::models::{InputMode, ViewMode};
use crate::tui::ui::main::ui;

struct TerminalGuard;

impl Drop for TerminalGuard {
    fn drop(&mut self) {
        let _ = disable_raw_mode();
        let mut stdout = io::stdout();
        let _ = execute!(stdout, LeaveAlternateScreen, crossterm::event::DisableMouseCapture);
    }
}

fn extract_message_text(content: &[ContentPart]) -> String {
    let mut out = String::new();
    for part in content {
        match part {
            ContentPart::Text { text } | ContentPart::Thinking { text } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(text);
            }
            ContentPart::ToolCall {
                name, arguments, ..
            } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(&format!("Tool call: {name} {arguments}"));
            }
            ContentPart::ToolResult { content, .. } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(content);
            }
            ContentPart::Image { url, .. } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(&format!("[image: {url}]"));
            }
            ContentPart::File { path, .. } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(&format!("[file: {path}]"));
            }
        }
    }
    out
}

fn sync_messages_from_session(app: &mut App, session: &Session) {
    app.state.messages = session
        .messages
        .iter()
        .filter_map(|msg| {
            let content = extract_message_text(&msg.content);
            if content.trim().is_empty() {
                return None;
            }
            let message_type = match msg.role {
                Role::User => MessageType::User,
                Role::Assistant => MessageType::Assistant,
                Role::System | Role::Tool => MessageType::System,
            };
            Some(ChatMessage::new(message_type, content))
        })
        .collect();
    app.state.scroll_to_bottom();
}

fn truncate_preview(text: &str, max_chars: usize) -> String {
    let mut chars = text.chars();
    let preview: String = chars.by_ref().take(max_chars).collect();
    if chars.next().is_some() {
        format!("{preview}…")
    } else {
        preview
    }
}

async fn refresh_sessions(app: &mut App, cwd: &std::path::Path) {
    match list_sessions_for_directory(cwd).await {
        Ok(sessions) => {
            app.state.sessions = sessions;
            if app.state.selected_session >= app.state.sessions.len() {
                app.state.selected_session = app.state.sessions.len().saturating_sub(1);
            }
        }
        Err(err) => {
            app.state.status = format!("Failed to list sessions: {err}");
            app.state.sessions.clear();
            app.state.selected_session = 0;
        }
    }
}

fn return_to_chat(app: &mut App) {
    app.state.set_view_mode(ViewMode::Chat);
    app.state.status = "Back to chat".to_string();
}

pub async fn run(project: Option<std::path::PathBuf>) -> anyhow::Result<()> {
    if let Some(project) = project {
        std::env::set_current_dir(&project)?;
    }

    enable_raw_mode()?;
    let _guard = TerminalGuard;

    let mut stdout = io::stdout();
    execute!(
        stdout,
        EnterAlternateScreen,
        crossterm::event::EnableMouseCapture
    )?;

    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;
    terminal.clear()?;

    let registry = ProviderRegistry::from_vault().await.ok().map(Arc::new);
    let cwd = std::env::current_dir().unwrap_or_default();
    let bus = AgentBus::new().into_arc();
    let mut bus_handle = bus.handle("tui");

    let mut session = match Session::last_for_directory(Some(&cwd)).await {
        Ok(existing) => existing,
        Err(_) => Session::new().await?,
    };

    let (event_tx, mut event_rx) = mpsc::channel::<SessionEvent>(256);
    let (result_tx, mut result_rx) = mpsc::channel::<anyhow::Result<Session>>(8);

    let mut app = App::default();
    app.state.cwd_display = cwd.display().to_string();
    app.state.session_id = Some(session.id.clone());
    sync_messages_from_session(&mut app, &session);
    refresh_sessions(&mut app, &cwd).await;
    if app.state.messages.is_empty() {
        app.state.status = "Ready — type a message and press Enter.".to_string();
    } else {
        app.state.status = "Loaded previous workspace session".to_string();
    }
    app.state.move_cursor_end();

    loop {
        while let Some(envelope) = bus_handle.try_recv() {
            app.state.bus_log.ingest(&envelope);
        }

        while let Ok(updated_session) = result_rx.try_recv() {
            match updated_session {
                Ok(updated_session) => {
                    session = updated_session;
                    app.state.session_id = Some(session.id.clone());
                    let _ = session.save().await;
                    refresh_sessions(&mut app, &cwd).await;
                }
                Err(err) => {
                    app.state.processing = false;
                    app.state
                        .messages
                        .push(ChatMessage::new(MessageType::Error, err.to_string()));
                    app.state.status = "Request failed".to_string();
                    app.state.scroll_to_bottom();
                }
            }
        }

        while let Ok(evt) = event_rx.try_recv() {
            match evt {
                SessionEvent::Thinking => {
                    app.state.processing = true;
                    app.state.status = "Thinking…".to_string();
                }
                SessionEvent::ToolCallStart { name, arguments } => {
                    app.state.processing = true;
                    app.state.status = format!("Running tool: {name}");
                    let args_preview = truncate_preview(&arguments, 240);
                    app.state.messages.push(ChatMessage::new(
                        MessageType::System,
                        format!("Tool start: {name}\nArgs: {args_preview}"),
                    ));
                    app.state.scroll_to_bottom();
                }
                SessionEvent::ToolCallComplete {
                    name,
                    output,
                    success,
                } => {
                    let output_preview = truncate_preview(&output, 600);
                    app.state.messages.push(ChatMessage::new(
                        if success {
                            MessageType::System
                        } else {
                            MessageType::Error
                        },
                        format!(
                            "Tool {}: {name}\nOutput: {output_preview}",
                            if success { "complete" } else { "failed" }
                        ),
                    ));
                    app.state.status = format!("Tool finished: {name}");
                    app.state.scroll_to_bottom();
                }
                SessionEvent::TextChunk(_) => {}
                SessionEvent::TextComplete(text) => {
                    app.state
                        .messages
                        .push(ChatMessage::new(MessageType::Assistant, text));
                    app.state.status = "Assistant replied".to_string();
                    app.state.scroll_to_bottom();
                }
                SessionEvent::ThinkingComplete(text) => {
                    if !text.is_empty() {
                        app.state.messages.push(ChatMessage::new(
                            MessageType::System,
                            format!("Thinking:\n{}", truncate_preview(&text, 600)),
                        ));
                        app.state.scroll_to_bottom();
                    }
                }
                SessionEvent::UsageReport {
                    model,
                    prompt_tokens,
                    completion_tokens,
                    duration_ms,
                } => {
                    app.state.status = format!(
                        "Completed with model {model} • {} in / {} out • {} ms",
                        prompt_tokens, completion_tokens, duration_ms
                    );
                }
                SessionEvent::SessionSync(updated) => {
                    session = *updated;
                    app.state.session_id = Some(session.id.clone());
                }
                SessionEvent::Done => {
                    app.state.processing = false;
                    app.state.status = "Ready".to_string();
                }
                SessionEvent::Error(err) => {
                    app.state.processing = false;
                    app.state
                        .messages
                        .push(ChatMessage::new(MessageType::Error, err.clone()));
                    app.state.status = "Error".to_string();
                    app.state.scroll_to_bottom();
                }
            }
        }

        terminal.draw(|f| ui(f, &mut app))?;

        if event::poll(Duration::from_millis(50))? {
            match event::read()? {
                Event::Key(key) if key.kind == KeyEventKind::Press => match key.code {
                    KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => break,
                    KeyCode::Char('q') if key.modifiers.contains(KeyModifiers::CONTROL) => break,
                    KeyCode::F(1) => app.state.set_view_mode(ViewMode::Help),
                    KeyCode::F(2) => {
                        if app.state.view_mode == ViewMode::Sessions {
                            return_to_chat(&mut app);
                        } else {
                            refresh_sessions(&mut app, &cwd).await;
                            app.state.set_view_mode(ViewMode::Sessions);
                            app.state.status = "Session picker".to_string();
                        }
                    }
                    KeyCode::F(3) => app.state.set_view_mode(ViewMode::Swarm),
                    KeyCode::F(4) => app.state.set_view_mode(ViewMode::Ralph),
                    KeyCode::F(5) => app.state.set_view_mode(ViewMode::Bus),
                    KeyCode::F(6) => app.state.set_view_mode(ViewMode::Settings),
                    KeyCode::F(7) => app.state.set_view_mode(ViewMode::Lsp),
                    KeyCode::F(8) => app.state.set_view_mode(ViewMode::Rlm),
                    KeyCode::Esc => match app.state.view_mode {
                        ViewMode::Sessions => return_to_chat(&mut app),
                        ViewMode::Swarm if app.state.swarm.detail_mode => app.state.swarm.exit_detail(),
                        ViewMode::Ralph if app.state.ralph.detail_mode => app.state.ralph.exit_detail(),
                        ViewMode::Bus if app.state.bus_log.detail_mode => app.state.bus_log.exit_detail(),
                        ViewMode::Chat => app.state.input_mode = InputMode::Normal,
                        _ => return_to_chat(&mut app),
                    },
                    KeyCode::Up => match app.state.view_mode {
                        ViewMode::Sessions => app.state.sessions_select_prev(),
                        ViewMode::Swarm => {
                            if app.state.swarm.detail_mode {
                                app.state.swarm.detail_scroll_up(1);
                            } else {
                                app.state.swarm.select_prev();
                            }
                        }
                        ViewMode::Ralph => {
                            if app.state.ralph.detail_mode {
                                app.state.ralph.detail_scroll_up(1);
                            } else {
                                app.state.ralph.select_prev();
                            }
                        }
                        ViewMode::Bus => {
                            if app.state.bus_log.detail_mode {
                                app.state.bus_log.detail_scroll_up(1);
                            } else {
                                app.state.bus_log.select_prev();
                            }
                        }
                        _ => app.state.scroll_up(1),
                    },
                    KeyCode::Down => match app.state.view_mode {
                        ViewMode::Sessions => app.state.sessions_select_next(),
                        ViewMode::Swarm => {
                            if app.state.swarm.detail_mode {
                                app.state.swarm.detail_scroll_down(1);
                            } else {
                                app.state.swarm.select_next();
                            }
                        }
                        ViewMode::Ralph => {
                            if app.state.ralph.detail_mode {
                                app.state.ralph.detail_scroll_down(1);
                            } else {
                                app.state.ralph.select_next();
                            }
                        }
                        ViewMode::Bus => {
                            if app.state.bus_log.detail_mode {
                                app.state.bus_log.detail_scroll_down(1);
                            } else {
                                app.state.bus_log.select_next();
                            }
                        }
                        _ => app.state.scroll_down(1),
                    },
                    KeyCode::PageUp => match app.state.view_mode {
                        ViewMode::Swarm if app.state.swarm.detail_mode => {
                            app.state.swarm.detail_scroll_up(10)
                        }
                        ViewMode::Ralph if app.state.ralph.detail_mode => {
                            app.state.ralph.detail_scroll_up(10)
                        }
                        ViewMode::Bus if app.state.bus_log.detail_mode => {
                            app.state.bus_log.detail_scroll_up(10)
                        }
                        ViewMode::Chat => app.state.scroll_up(10),
                        _ => {}
                    },
                    KeyCode::PageDown => match app.state.view_mode {
                        ViewMode::Swarm if app.state.swarm.detail_mode => {
                            app.state.swarm.detail_scroll_down(10)
                        }
                        ViewMode::Ralph if app.state.ralph.detail_mode => {
                            app.state.ralph.detail_scroll_down(10)
                        }
                        ViewMode::Bus if app.state.bus_log.detail_mode => {
                            app.state.bus_log.detail_scroll_down(10)
                        }
                        ViewMode::Chat => app.state.scroll_down(10),
                        _ => {}
                    },
                    KeyCode::Home => {
                        if app.state.view_mode == ViewMode::Chat {
                            app.state.move_cursor_home();
                        }
                    }
                    KeyCode::End => {
                        if app.state.view_mode == ViewMode::Chat {
                            app.state.move_cursor_end();
                        }
                    }
                    KeyCode::Left => {
                        if app.state.view_mode == ViewMode::Chat && !app.state.processing {
                            if key.modifiers.contains(KeyModifiers::CONTROL) {
                                app.state.move_cursor_word_left();
                            } else {
                                app.state.move_cursor_left();
                            }
                        }
                    }
                    KeyCode::Right => {
                        if app.state.view_mode == ViewMode::Chat && !app.state.processing {
                            if key.modifiers.contains(KeyModifiers::CONTROL) {
                                app.state.move_cursor_word_right();
                            } else {
                                app.state.move_cursor_right();
                            }
                        }
                    }
                    KeyCode::Delete => {
                        if app.state.view_mode == ViewMode::Chat && !app.state.processing {
                            app.state.delete_forward();
                        }
                    }
                    KeyCode::Enter => match app.state.view_mode {
                        ViewMode::Sessions => {
                            if let Some(summary) = app.state.sessions.get(app.state.selected_session) {
                                match Session::load(&summary.id).await {
                                    Ok(loaded) => {
                                        session = loaded;
                                        app.state.session_id = Some(session.id.clone());
                                        sync_messages_from_session(&mut app, &session);
                                        refresh_sessions(&mut app, &cwd).await;
                                        return_to_chat(&mut app);
                                        app.state.status = format!(
                                            "Loaded session {}",
                                            session.title.clone().unwrap_or_else(|| session.id.clone())
                                        );
                                    }
                                    Err(err) => {
                                        app.state.status = format!("Failed to load session: {err}");
                                    }
                                }
                            }
                        }
                        ViewMode::Swarm => app.state.swarm.enter_detail(),
                        ViewMode::Ralph => app.state.ralph.enter_detail(),
                        ViewMode::Bus => app.state.bus_log.enter_detail(),
                        ViewMode::Chat => {
                            if app.state.processing {
                                app.state.status = "Still processing previous request…".to_string();
                            } else {
                                let prompt = app.state.input.trim().to_string();
                                if !prompt.is_empty() {
                                    app.state
                                        .messages
                                        .push(ChatMessage::new(MessageType::User, prompt.clone()));
                                    app.state.input.clear();
                                    app.state.input_cursor = 0;
                                    app.state.input_scroll = 0;
                                    app.state.processing = true;
                                    app.state.status = "Submitting prompt…".to_string();
                                    app.state.scroll_to_bottom();

                                    if let Some(registry) = &registry {
                                        let mut session_for_task = session.clone();
                                        let event_tx = event_tx.clone();
                                        let result_tx = result_tx.clone();
                                        let registry = Arc::clone(registry);
                                        tokio::spawn(async move {
                                            let result = session_for_task
                                                .prompt_with_events(&prompt, event_tx, registry)
                                                .await
                                                .map(|_| session_for_task);
                                            let _ = result_tx.send(result).await;
                                        });
                                    } else {
                                        app.state.processing = false;
                                        app.state.messages.push(ChatMessage::new(
                                            MessageType::Error,
                                            "No providers available. Configure credentials first (for example: `codetether auth codex` or `codetether auth copilot`).",
                                        ));
                                        app.state.status = "No providers configured".to_string();
                                        app.state.scroll_to_bottom();
                                    }
                                }
                            }
                        }
                        _ => {}
                    },
                    KeyCode::Backspace => {
                        if app.state.view_mode == ViewMode::Chat && !app.state.processing {
                            app.state.delete_backspace();
                        }
                    }
                    KeyCode::Char('g') if app.state.view_mode == ViewMode::Bus => {
                        let len = app.state.bus_log.visible_count();
                        if len > 0 {
                            app.state.bus_log.selected_index = len - 1;
                            app.state.bus_log.auto_scroll = true;
                        }
                    }
                    KeyCode::Char('c') if app.state.view_mode == ViewMode::Bus => {
                        app.state.bus_log.filter.clear();
                    }
                    KeyCode::Char('/') if app.state.view_mode == ViewMode::Bus => {
                        app.state.status = "Bus filter editing not yet interactive; press c to clear current filter".to_string();
                    }
                    KeyCode::Char(c) => {
                        if app.state.view_mode == ViewMode::Chat
                            && !key.modifiers.contains(KeyModifiers::CONTROL)
                            && !key.modifiers.contains(KeyModifiers::ALT)
                            && !app.state.processing
                        {
                            app.state.input_mode = InputMode::Editing;
                            app.state.insert_char(c);
                        }
                    }
                    _ => {}
                },
                Event::Resize(_, _) => {}
                _ => {}
            }
        }
    }

    terminal.show_cursor()?;
    Ok(())
}
"}

