 58 | /// A tool that can be executed by an agent
 59 | #[async_trait]
 60 | pub trait Tool: Send + Sync {
 61 |     /// Tool identifier
 62 |     fn id(&self) -> &str;
 63 | 
 64 |     /// Human-readable name
 65 |     fn name(&self) -> &str;
 66 | 
 67 |     /// Description for the LLM
 68 |     fn description(&self) -> &str;
 69 | 
 70 |     /// JSON Schema for parameters
 71 |     fn parameters(&self) -> Value;
 72 | 
 73 |     /// Execute the tool with given arguments
 74 |     async fn execute(&self, args: Value) -> Result<ToolResult>;
 75 | }
 76 | 
 77 | /// Result from tool execution
 78 | #[derive(Debug, Clone, Serialize, Deserialize)]
 79 | pub struct ToolResult {
 80 |     pub output: String,
 81 |     pub success: bool,
 82 |     #[serde(default)]
 83 |     pub metadata: HashMap<String, Value>,
 84 | }
 85 | 
 86 | impl ToolResult {
 87 |     pub fn success(output: impl Into<String>) -> Self {
 88 |         Self {
 89 |             output: output.into(),
 90 |             success: true,
 91 |             metadata: HashMap::new(),
 92 |         }
 93 |     }
 94 | 
 95 |     pub fn error(message: impl Into<String>) -> Self {
 96 |         Self {
 97 |             output: message.into(),
 98 |             success: false,
 99 |             metadata: HashMap::new(),
100 |         }
101 |     }
102 | 
103 |     /// Create a structured error with code, tool name, missing fields, and example
104 |     ///
105 |     /// This helps LLMs self-correct by providing actionable information about what went wrong.
106 |     pub fn structured_error(
107 |         code: &str,
108 |         tool: &str,
109 |         message: &str,
110 |         missing_fields: Option<Vec<&str>>,
111 |         example: Option<Value>,
112 |     ) -> Self {
113 |         let mut error_obj = serde_json::json!({
114 |             "code": code,
115 |             "tool": tool,
116 |             "message": message,
117 |         });
118 | 
119 |         if let Some(fields) = missing_fields {
120 |             error_obj["missing_fields"] = serde_json::json!(fields);
121 |         }
122 | 
123 |         if let Some(ex) = example {
124 |             error_obj["example"] = ex;
125 |         }
126 | 
127 |         let output = serde_json::to_string_pretty(&serde_json::json!({
128 |             "error": error_obj
129 |         }))
130 |         .unwrap_or_else(|_| format!("Error: {}", message));
131 | 
132 |         let mut metadata = HashMap::new();
133 |         metadata.insert("error_code".to_string(), serde_json::json!(code));
134 |         metadata.insert("tool".to_string(), serde_json::json!(tool));
135 | 
136 |         Self {
137 |             output,
138 |             success: false,
139 |             metadata,
140 |         }
141 |     }
142 | 
143 |     pub fn with_metadata(mut self, key: impl Into<String>, value: Value) -> Self {
144 |         self.metadata.insert(key.into(), value);
145 |         self
146 |     }
147 | }
