150 | pub struct ToolRegistry {
151 |     tools: HashMap<String, Arc<dyn Tool>>,
152 |     plugin_registry: PluginRegistry,
153 | }
154 | 
155 | impl std::fmt::Debug for ToolRegistry {
156 |     fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
157 |         f.debug_struct("ToolRegistry")
158 |             .field("tools", &self.tools.keys().collect::<Vec<_>>())
159 |             .finish()
160 |     }
161 | }
