163 | impl ToolRegistry {
164 |     pub fn new() -> Self {
165 |         let _ = std::any::TypeId::of::<McpToolManager>();
166 |         let _ = std::any::TypeId::of::<McpToolWrapper>();
167 |         Self {
168 |             tools: HashMap::new(),
169 |             plugin_registry: PluginRegistry::from_env(),
170 |         }
171 |     }
172 | 
173 |     /// Get a reference to the plugin registry for managing signed plugins.
174 |     pub fn plugins(&self) -> &PluginRegistry {
175 |         &self.plugin_registry
176 |     }
177 | 
178 |     /// Register a tool
179 |     pub fn register(&mut self, tool: Arc<dyn Tool>) {
180 |         self.tools.insert(tool.id().to_string(), tool);
181 |     }
182 | 
183 |     /// Get a tool by ID
184 |     pub fn get(&self, id: &str) -> Option<Arc<dyn Tool>> {
185 |         self.tools.get(id).cloned()
186 |     }
187 | 
188 |     /// List all tool IDs
189 |     pub fn list(&self) -> Vec<&str> {
190 |         self.tools.keys().map(|s| s.as_str()).collect()
191 |     }
192 | 
193 |     /// Get tool definitions for LLM
194 |     pub fn definitions(&self) -> Vec<crate::provider::ToolDefinition> {
195 |         self.tools
196 |             .values()
197 |             .map(|t| crate::provider::ToolDefinition {
198 |                 name: t.id().to_string(),
199 |                 description: t.description().to_string(),
200 |                 parameters: t.parameters(),
201 |             })
202 |             .collect()
203 |     }
204 | 
205 |     /// Register multiple tools at once
206 |     pub fn register_all(&mut self, tools: Vec<Arc<dyn Tool>>) {
207 |         for tool in tools {
208 |             self.register(tool);
209 |         }
210 |     }
211 | 
212 |     /// Remove a tool by ID
213 |     pub fn unregister(&mut self, id: &str) -> Option<Arc<dyn Tool>> {
214 |         self.tools.remove(id)
215 |     }
216 | 
217 |     /// Check if a tool exists
218 |     pub fn contains(&self, id: &str) -> bool {
219 |         self.tools.contains_key(id)
220 |     }

