 15 |     std::sync::OnceLock::new();
 16 | 
 17 | #[derive(Debug, Clone, Copy, PartialEq, Eq)]
 18 | enum LspOperation {
 19 |     GoToDefinition,
 20 |     FindReferences,
 21 |     Hover,
 22 |     DocumentSymbol,
 23 |     WorkspaceSymbol,
 24 |     GoToImplementation,
 25 |     Completion,
 26 |     Diagnostics,
 27 | }
 28 | 
 29 | impl LspOperation {
 30 |     fn parse(action: &str) -> Option<Self> {
 31 |         match action {
 32 |             "goToDefinition" | "go-to-definition" | "go_to_definition" => {
 33 |                 Some(Self::GoToDefinition)
 34 |             }
 35 |             "findReferences" | "find-references" | "find_references" => Some(Self::FindReferences),
 36 |             "hover" => Some(Self::Hover),
 37 |             "documentSymbol" | "document-symbol" | "document_symbol" => Some(Self::DocumentSymbol),
 38 |             "workspaceSymbol" | "workspace-symbol" | "workspace_symbol" => {
 39 |                 Some(Self::WorkspaceSymbol)
 40 |             }
 41 |             "goToImplementation" | "go-to-implementation" | "go_to_implementation" => {
 42 |                 Some(Self::GoToImplementation)
 43 |             }
 44 |             "completion" => Some(Self::Completion),
 45 |             "diagnostics" => Some(Self::Diagnostics),
 46 |             _ => None,
 47 |         }
 48 |     }
 49 | 
 50 |     fn requires_position(self) -> bool {
 51 |         match self {
 52 |             Self::GoToDefinition
 53 |             | Self::FindReferences
 54 |             | Self::Hover
