 93 |     if let Some(action) = args["action"].as_str() {
 94 |         return Ok(action.to_string());
 95 |     }
 96 | 
 97 |     if let Some(command) = args["command"].as_str() {
 98 |         if let Some(mapped) = action_from_command(command) {
