 31 | fn extract_message_text(content: &[ContentPart]) -> String {
 32 |     let mut out = String::new();
 33 |     for part in content {
 34 |         match part {
 35 |             ContentPart::Text { text } | ContentPart::Thinking { text } => {
 36 |                 if !out.is_empty() {
 37 |                     out.push('\n');
 38 |                 }
 39 |                 out.push_str(text);
 40 |             }
 41 |             ContentPart::ToolCall {
 42 |                 name, arguments, ..
 43 |             } => {
 44 |                 if !out.is_empty() {
 45 |                     out.push('\n');
 46 |                 }
 47 |                 out.push_str(&format!("Tool call: {name} {arguments}"));
 48 |             }
 49 |             ContentPart::ToolResult { content, .. } => {
 50 |                 if !out.is_empty() {
 51 |                     out.push('\n');
 52 |                 }
 53 |                 out.push_str(content);
 54 |             }
 55 |             ContentPart::Image { url, .. } => {
 56 |                 if !out.is_empty() {
 57 |                     out.push('\n');
 58 |                 }
 59 |                 out.push_str(&format!("[image: {url}]"));
 60 |             }
 61 |             ContentPart::File { path, .. } => {
 62 |                 if !out.is_empty() {
 63 |                     out.push('\n');
 64 |                 }
 65 |                 out.push_str(&format!("[file: {path}]"));
 66 |             }
 67 |         }
 68 |     }
 69 |     out
 70 | }
